import { useState } from "react";
import GlowAndShine from "./GlowAndShine";
import ServicesPage from "./pages/ServicesPage";

export default function App() {
  const [page, setPage] = useState("home"); // "home" | "services"

  if (page === "services") {
    return <ServicesPage onNavigate={(p) => setPage(p === "home" ? "home" : p)} />;
  }

  // Pass the navigate callback down to GlowAndShine
  return <GlowAndShine onExplore={() => setPage("services")} />;
}
